@app.route('/oauth/token/revoke', methods=['POST'])
def revoke_token():
    data = request.get_json()
    token = data.get('token')
    
    if not token:
        return jsonify({'error': 'token_required'}), 400
    
    db = get_db()
    db.execute('UPDATE access_tokens SET revoked = 1 WHERE token = ?', (token,))
    db.commit()
    
    return jsonify({'message': 'Token revoked successfully'})

@app.route('/oauth/token/create', methods=['POST'])
def create_token():
    data = request.get_json()
    
    client_id = data.get('client_id')
    user_id = data.get('user_id')
    scope = data.get('scope', 'read')
    expires_in = data.get('expires_in', 3600)
    
    if not client_id:
        return jsonify({'error': 'client_id_required'}), 400
    
    token = secrets.token_urlsafe(32)
    expires_at = datetime.now().timestamp() + expires_in
    expires_at_str = datetime.fromtimestamp(expires_at).isoformat()
    
    db = get_db()
    db.execute('''
        INSERT INTO access_tokens (token, client_id, user_id, scope, expires_at)
        VALUES (?, ?, ?, ?, ?)
    ''', (token, client_id, user_id, scope, expires_at_str))
    db.commit()
    
    return jsonify({
        'access_token': token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scope': scope
    })

